     {q:"In feudal Japan, the shogun held ___.", options:["No connection to government","Only religious authority","Significant military power","No power at all"], answer:2},
     {q:"Samurai were known as ___.", options:["Skilled warriors bound by a code of honour","Government officials with no military training","Foreign traders","Farmers with no military role"], answer:0},
     {q:"Feudal Japan was organized around a ___.", options:["Strict social hierarchy","A system with no leaders","Complete lack of social structure","A structure identical to modern Japan"], answer:0},
     {q:"The samurai code of honour emphasized values such as ___.", options:["Avoiding all responsibility","Dishonesty and disorder","Loyalty and discipline","Ignoring any code of conduct"], answer:2},
     {q:"Why is feudal Japan studied as part of world history?", options:["It has no historical significance","It is identical to feudal systems everywhere else","Feudal Japan never actually existed","It offers insight into a distinct social and political system that shaped Japanese history"], answer:3}
